#include <bits/stdc++.h>
using namespace std;

int N;  // カッコ列の長さ（グローバル変数として共有）

// s: 今まで作った文字列
// l: 置いた '(' の数
// r: 置いた ')' の数
void solve(string s, int l, int r) {
    if ((int)s.size() == N) {  // 長さが N になったら出力
        cout << s << '\n';
        return;
    }
    if (l < N / 2)  // まだ '(' を置ける（合計 N/2 個まで）
        solve(s + '(', l + 1, r);
    if (r < l)      // 閉じていない '(' があるので ')' を置ける
        solve(s + ')', l, r + 1);
}

int main() {
    cin >> N;
    if (N % 2 == 0)  // 奇数のときは正しいカッコ列が存在しない
        solve("", 0, 0);
}

